proof_block:
broadcast use vstd::std_specs::vec::group_vec_axioms;
broadcast use vstd::std_specs::vec::lemma_vec_obeys_view_eq;

assert(({
    &&& (SingleDelivery::maybe_ack_packet(self_@, pkt@, r1.unwrap()@, CSingleDelivery::option_cpacket_to_set_packet(r1)))
    &&& (r1 is Some ==> valid_ack(r1.unwrap(), pkt))
    &&& (SingleDelivery::maybe_ack_packet(self_@, pkt@, r2.unwrap()@, CSingleDelivery::option_cpacket_to_set_packet(r2)))
    &&& (r2 is Some ==> valid_ack(r2.unwrap(), pkt))
}) ==> det_maybe_ack_packet_impl_equal(r1, r2)) by {
    let pre = self_@;
    let p = pkt@;
    let s1 = CSingleDelivery::option_cpacket_to_set_packet(r1);
    let s2 = CSingleDelivery::option_cpacket_to_set_packet(r2);

    if (SingleDelivery::maybe_ack_packet(pre, p, r1.unwrap()@, s1))
       && (r1 is Some ==> valid_ack(r1.unwrap(), pkt))
       && (SingleDelivery::maybe_ack_packet(pre, p, r2.unwrap()@, s2))
       && (r2 is Some ==> valid_ack(r2.unwrap(), pkt)) {

        // `should_ack_single_message(self_@, pkt@)` is fully determined by
        // (self_, pkt) and therefore agrees on both runs.  Case-split on it
        // and instantiate `option_cpacket_to_set_packet` on each side so
        // the Some/None tag of r1 and r2 is forced to coincide.
        if pre.should_ack_single_message(p) {
            // send_ack pins acks == set![ack]; a singleton can't be empty,
            // so r being None (which produces Set::empty()) is impossible.
            if r1 is None {
                assert(s1 =~= Set::<Packet>::empty());
                assert(SingleDelivery::send_ack(pre, p, r1.unwrap()@, s1));
                assert(s1 =~= set!{ r1.unwrap()@ });
                assert(s1.contains(r1.unwrap()@));
                assert(false);
            }
            if r2 is None {
                assert(s2 =~= Set::<Packet>::empty());
                assert(SingleDelivery::send_ack(pre, p, r2.unwrap()@, s2));
                assert(s2 =~= set!{ r2.unwrap()@ });
                assert(s2.contains(r2.unwrap()@));
                assert(false);
            }
            assert(r1 is Some);
            assert(r2 is Some);

            // send_ack pins ack.src@/ack.dst@ to pkt.dst@/pkt.src@.
            assert(SingleDelivery::send_ack(pre, p, r1.unwrap()@, s1));
            assert(SingleDelivery::send_ack(pre, p, r2.unwrap()@, s2));
            assert(r1.unwrap()@.src == p.dst);
            assert(r2.unwrap()@.src == p.dst);
            assert(r1.unwrap()@.dst == p.src);
            assert(r2.unwrap()@.dst == p.src);
            // CPacket@'s src/dst are AbstractEndPoint { id: self.src.id@ }.
            assert(r1.unwrap().src@ == r2.unwrap().src@);
            assert(r1.unwrap().dst@ == r2.unwrap().dst@);
            assert(r1.unwrap().src.id@ == r2.unwrap().src.id@);
            assert(r1.unwrap().dst.id@ == r2.unwrap().dst.id@);

            // send_ack also pins ack.msg to an Ack with the message's seqno;
            // CSingleMessage::Ack carries a single u64, so equal seqnos
            // collapse via structural enum equality.
            assert(r1.unwrap()@.msg is Ack);
            assert(r2.unwrap()@.msg is Ack);
            assert(r1.unwrap().msg is Ack);
            assert(r2.unwrap().msg is Ack);
            assert(r1.unwrap().msg.arrow_Ack_ack_seqno()
                == pkt.msg.arrow_Message_seqno());
            assert(r2.unwrap().msg.arrow_Ack_ack_seqno()
                == pkt.msg.arrow_Message_seqno());
            assert(r1.unwrap().msg.arrow_Ack_ack_seqno()
                == r2.unwrap().msg.arrow_Ack_ack_seqno());
            assert(r1.unwrap().msg == r2.unwrap().msg);
        } else {
            // !should_ack ⇒ acks.is_empty(); a singleton set cannot be empty,
            // so r being Some is impossible.
            if r1 is Some {
                assert(s1 =~= set!{ r1.unwrap()@ });
                assert(s1.is_empty());
                assert(s1.contains(r1.unwrap()@));
                assert(false);
            }
            if r2 is Some {
                assert(s2 =~= set!{ r2.unwrap()@ });
                assert(s2.is_empty());
                assert(s2.contains(r2.unwrap()@));
                assert(false);
            }
            assert(r1 is None);
            assert(r2 is None);
        }
    }
};
